class Solution:
    def maximumGap(self, nums):
        if len(nums) < 2:
            return 0
        s = sorted(nums)
        best = 0
        for i in range(1, len(s)):
            d = s[i] - s[i - 1]
            if d > best:
                best = d
        return best

