class Solution:
    def maximumGap(self, nums):
        n = len(nums)
        if n < 2:
            return 0
        lo, hi = min(nums), max(nums)
        if lo == hi:
            return 0
        import math
        bucket_size = max(1, (hi - lo) // (n - 1))
        bucket_count = (hi - lo) // bucket_size + 1
        bmin = [None] * bucket_count
        bmax = [None] * bucket_count
        for x in nums:
            idx = (x - lo) // bucket_size
            if bmin[idx] is None or x < bmin[idx]:
                bmin[idx] = x
            if bmax[idx] is None or x > bmax[idx]:
                bmax[idx] = x
        best = 0
        prev_max = lo
        for i in range(bucket_count):
            if bmin[i] is None:
                continue
            best = max(best, bmin[i] - prev_max)
            prev_max = bmax[i]
        return best

