var maximumGap = function(nums) {
    const n = nums.length;
    if (n < 2) return 0;
    let lo = Infinity, hi = -Infinity;
    for (const x of nums) { if (x < lo) lo = x; if (x > hi) hi = x; }
    if (lo === hi) return 0;
    const bucketSize = Math.max(1, Math.floor((hi - lo) / (n - 1)));
    const bucketCount = Math.floor((hi - lo) / bucketSize) + 1;
    const bmin = new Array(bucketCount).fill(null);
    const bmax = new Array(bucketCount).fill(null);
    for (const x of nums) {
        const idx = Math.floor((x - lo) / bucketSize);
        if (bmin[idx] === null || x < bmin[idx]) bmin[idx] = x;
        if (bmax[idx] === null || x > bmax[idx]) bmax[idx] = x;
    }
    let best = 0, prevMax = lo;
    for (let i = 0; i < bucketCount; i++) {
        if (bmin[i] === null) continue;
        best = Math.max(best, bmin[i] - prevMax);
        prevMax = bmax[i];
    }
    return best;
};
